member.example:
Bind the BoxCollider size property using a serialized binder field — the target BoxCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private BoxColliderSizeBinder _size;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _size;
    }


Bind the BoxCollider size property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private BoxCollider _boxCollider;
        
        private BoxColliderSizeBinder Size =>
            new(_boxCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _size;
    }

Switch the BoxCollider size between two Vector3 values using a serialized binder field — the target BoxCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private BoxColliderSizeSwitcherBinder _isExpanded;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }


Switch the BoxCollider size between two Vector3 values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private BoxCollider _boxCollider;
        
        private BoxColliderSizeSwitcherBinder IsExpanded => new(
            _boxCollider,
            trueValue: new Vector3(2, 2, 2),
            falseValue: Vector3.one);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }
